    const stageDurationSec = Math.max(1, parseDurationToSec(stage.duration));
    stageDurationSecMap[stageIndex] = stageDurationSec;
    const windowCount = Math.max(1, Math.ceil(stageDurationSec / WINDOW_SEC));
